#[test]
fn test_custom_block_reward_post_merge() {
    // Test that custom block rewards are applied to the beneficiary after block execution
    let custom_reward = 2 * ETH_TO_WEI; // 2 ETH custom block reward
    let beneficiary = address!("0xdeadbeefdeadbeefdeadbeefdeadbeefdeadbeef");

    // Create chain spec with Paris activated at genesis and custom block reward
    let chain_spec = Arc::new(
        ChainSpecBuilder::from(&*MAINNET)
            .shanghai_activated()
            .with_fork(
                EthereumHardfork::Paris,
                ForkCondition::TTD {
                    total_difficulty: U256::ZERO,
                    activation_block_number: 0,
                    fork_block: None,
                },
            )
            .base_block_reward(Some(custom_reward))
            .build(),
